SET SQL DIALECT 3;

CREATE TABLE LFCES004 (
    UNIDADE_ID   INTEGER NOT NULL,
    CNES         CHAR(7) NOT NULL,
    NOME_FANTA   VARCHAR(100),
    CNPJ_MANT    CHAR(14),
    TP_UNID_ID   VARCHAR(3),
    CODMUNGEST   CHAR(6),
    PRIMARY KEY (UNIDADE_ID)
);

CREATE TABLE LFCES018 (
    PROF_ID      INTEGER NOT NULL,
    CPF_PROF     CHAR(11),
    COD_CNS      CHAR(15),
    NOME_PROF    VARCHAR(100),
    NO_SOCIAL    VARCHAR(100),
    SEXO         CHAR(1),
    DATA_NASC    VARCHAR(10),
    PRIMARY KEY (PROF_ID)
);

CREATE TABLE LFCES021 (
    PROF_ID         INTEGER NOT NULL,
    UNIDADE_ID      INTEGER NOT NULL,
    COD_CBO         CHAR(6),
    IND_VINC        CHAR(6),
    TP_SUS_NAO_SUS  CHAR(1),
    CG_HORAAMB      INTEGER,
    CGHORAOUTR      INTEGER,
    CGHORAHOSP      INTEGER,
    PRIMARY KEY (PROF_ID, UNIDADE_ID)
);





COMMIT;

